mapper.sql:
and a.recovery = 0
and (a.id = #{key} or a.name like CONCAT('%',#{key},'%'))
and a.status=#{status}
and a.store_id=#{storeId}
and a.starttime   >=   #{startDate}
and a.endtime   <=   #{endDate}
and a.mch_id = #{mchId}

mapper.select:
SELECT a.id, a.discount, a.buylimit, a.fsGoodsId, a.goodsId, a.fsMaxStockNum, a.goodsName, a.imgUrl, a.fsStatus, a.remainingTime, a.goodsPrice, a.mch_id, a.pId FROM ( SELECT b.id, b.discount, b.buylimit, b.id AS fsGoodsId, b.goods_id AS goodsId, p.num AS fsMaxStockNum, p.product_title AS goodsName, p.imgurl AS imgUrl, a.STATUS AS fsStatus, a.endtime AS remainingTime, c.price AS goodsPrice, a.mch_id, p.id AS pId, ROW_NUMBER() over (PARTITION by p.id ) AS top FROM lkt_flashsale_label a RIGHT JOIN lkt_flashsale_activity b ON a.id = b.label_id INNER JOIN lkt_product_list p ON b.goods_id = p.id LEFT JOIN lkt_configure AS c ON p.id = c.pid WHERE a.store_id = #{storeId} AND a.STATUS = 2 AND recovery = 0 AND c.recycle = 0
AND a.mch_id = #{mchId}
AND p.product_title LIKE CONCAT( '%',#{key}, '%' )
) as a where a.top < 2
